package org.matheclipse.core.reflection.system;

import org.matheclipse.core.eval.EvalEngine;
import org.matheclipse.core.eval.interfaces.AbstractFunctionEvaluator;
import org.matheclipse.core.expression.F;
import org.matheclipse.core.interfaces.IAST;
import org.matheclipse.core.interfaces.IASTAppendable;
import org.matheclipse.core.interfaces.IExpr;
import org.matheclipse.core.interfaces.ISymbol;

/**
 * <pre>
 * MatrixFunction(f, m)
 * </pre>
 * 
 * * <blockquote>
 * <p>
 * gives the matrix generated by the scalar function f at the matrix argument m.
 * </p>
 * </blockquote>
 */
public class MatrixFunction extends AbstractFunctionEvaluator {

  @Override
  public IExpr evaluate(final IAST ast, EvalEngine engine) {
    IExpr f = ast.arg1();
    IExpr m = ast.arg2();

    // MatrixFunction works only on square matrices
    int[] dims = m.isMatrix();
    if (dims == null || dims[0] != dims[1]) {
      return F.NIL;
    }
    int n = dims[0];

    // Diagonalization approach using Eigensystem(m) -> {eigenvalues, eigenvectors}
    IExpr eigenResult = engine.evaluate(F.Eigensystem(m));

    if (eigenResult.isList() && eigenResult.argSize() == 2) {
      IExpr eigenvalues = ((IAST) eigenResult).arg1();
      IExpr eigenvectors = ((IAST) eigenResult).arg2();

      if (eigenvalues.isList() && eigenvectors.isList()) {
        IAST valsList = (IAST) eigenvalues;
        IAST vecsList = (IAST) eigenvectors;

        // Evaluate f at each eigenvalue to construct the diagonal matrix D
        IASTAppendable fVals = F.ListAlloc(n);
        for (int i = 1; i <= n; i++) {
          fVals.append(engine.evaluate(F.unaryAST1(f, valsList.get(i))));
        }

        IAST diagonalMatrix = F.DiagonalMatrix(fVals);

        // The eigenvectors are the rows, so we transpose to get the transformation matrix S
        IAST sMatrix = (IAST) engine.evaluate(F.Transpose(vecsList));

        // Compute Inverse(S)
        IExpr sInverse = engine.evaluate(F.Inverse(sMatrix));

        // Check if the eigenvectors matrix is invertible (i.e., matrix is diagonalizable)
        if (sInverse.isList()) {
          // Compute f(M) = S . f(D) . S^(-1)
          return engine.evaluate(F.Dot(sMatrix, F.Dot(diagonalMatrix, sInverse)));
        }
      }
    }

    // Fallback strategy using JordanDecomposition
    // Handles defective (non-diagonalizable) matrices by expanding the Taylor series
    // of f(x) over the superdiagonals of each Jordan block.
    IExpr jordanResult = engine.evaluate(F.JordanDecomposition(m));
    if (jordanResult.isList2()) {
      IExpr s = ((IAST) jordanResult).arg1();
      IExpr jExpr = ((IAST) jordanResult).arg2();
      if (s.isList() && jExpr.isList()) {
        IAST j = (IAST) jExpr;

        // Initialize the f(J) matrix with zeros
        IASTAppendable resultJ = F.ListAlloc(n);
        for (int i = 0; i < n; i++) {
          IASTAppendable row = F.ListAlloc(n);
          for (int c = 0; c < n; c++) {
            row.append(F.C0);
          }
          resultJ.append(row);
        }

        // Setup f(x) for symbolic derivation
        ISymbol x = F.Dummy("x");
        IExpr fx = engine.evaluate(F.unaryAST1(f, x));

        int i = 1;
        while (i <= n) {
          int blockSize = 1;
          IExpr lambda = j.getPart(i, i);

          // Determine the size of the current Jordan block
          while (i + blockSize <= n && j.getPart(i + blockSize - 1, i + blockSize).isOne()) {
            blockSize++;
          }

          // Precompute f(lambda), f'(lambda)/1!, f''(lambda)/2!, ..., f^(k)(lambda)/k!
          IExpr[] terms = new IExpr[blockSize];
          IExpr currentDeriv = fx;
          terms[0] = engine.evaluate(F.subst(currentDeriv, F.Rule(x, lambda)));

          long factorial = 1;
          for (int d = 1; d < blockSize; d++) {
            currentDeriv = engine.evaluate(F.D(currentDeriv, x));
            factorial *= d;
            IExpr val = engine.evaluate(F.subst(currentDeriv, F.Rule(x, lambda)));
            terms[d] = engine.evaluate(F.Divide(val, F.ZZ(factorial)));
          }

          // Populate the upper triangular part of the current Jordan block
          for (int r = 0; r < blockSize; r++) {
            for (int c = r; c < blockSize; c++) {
              ((IASTAppendable) resultJ.get(i + r)).set(i + c, terms[c - r]);
            }
          }
          i += blockSize;
        }

        // Compute f(A) = S . f(J) . Inverse(S)
        IExpr sInverse = engine.evaluate(F.Inverse(s));
        if (sInverse.isList()) {
          return engine.evaluate(F.Dot(s, F.Dot(resultJ, sInverse)));
        }
      }
    }

    return F.NIL;
  }

  @Override
  public int[] expectedArgSize(IAST ast) {
    return ARGS_2_2;
  }
}
